#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: List Unity Catalog objects (catalogs, schemas, tables)
 *
 * This example demonstrates:
 * - Listing all catalogs in a workspace
 * - Listing schemas in a catalog
 * - Listing tables in a schema
 * - Displaying object hierarchy and properties
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 * - Unity Catalog enabled workspace
 *
 * Usage:
 *   npx ts-node examples/workspace/catalog/list-tables.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    console.log("Listing Unity Catalog hierarchy...\n");

    try {
        // List all catalogs
        console.log("=== CATALOGS ===\n");
        const catalogs = [];

        for await (const catalog of client.catalogs.list({})) {
            catalogs.push({
                "Name": catalog.name,
                "Full Name": catalog.full_name,
                "Owner": catalog.owner,
                "Comment": catalog.comment || "",
            });

            // List schemas in this catalog (limit to first 3 for brevity)
            const schemas = [];
            for await (const schema of client.schemas.list({
                catalog_name: catalog.name!,
            })) {
                schemas.push({
                    "Name": schema.name,
                    "Full Name": schema.full_name,
                });

                if (schemas.length >= 3) {
                    break;
                }
            }

            if (schemas.length > 0) {
                console.log(`\nSchemas in ${catalog.name}:`);
                console.table(schemas);
                if (schemas.length >= 3) {
                    console.log(`(showing first 3 schemas)\n`);
                }
            }
        }

        if (catalogs.length === 0) {
            console.log("No catalogs found in workspace.");
            return;
        }

        console.table(catalogs);

        // Example: List tables in a specific catalog.schema
        console.log("\n=== TABLES IN A SPECIFIC SCHEMA ===\n");
        console.log("Listing tables in main.default:\n");

        // Try to list tables in main.default (common default schema)
        try {
            const tables = [];

            for await (const table of client.tables.list({
                catalog_name: "main",
                schema_name: "default",
            })) {
                tables.push({
                    "Name": table.name,
                    "Full Name": table.full_name,
                    "Table Type": table.table_type,
                    "Data Source Format": table.data_source_format || "N/A",
                    "Owner": table.owner,
                    "Comment": table.comment || "",
                });

                if (tables.length >= 5) {
                    break;
                }
            }

            if (tables.length === 0) {
                console.log("No tables found in main.default");
            } else {
                console.table(tables);
                if (tables.length >= 5) {
                    console.log(`(showing first 5 tables)\n`);
                }
            }
        } catch (error) {
            console.log(
                "Could not list tables in main.default (catalog/schema may not exist)"
            );
        }

        console.log(`\n✓ Catalog listing complete`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
